alter table public.profiles enable row level security; alter table public.organizations enable row level security; alter table public.organization_members enable row level security;
alter table public.projects enable row level security; alter table public.tasks enable row level security; alter table public.customers enable row level security; alter table public.leads enable row level security; alter table public.meetings enable row level security; alter table public.documents enable row level security; alter table public.support_requests enable row level security; alter table public.conversations enable row level security; alter table public.ai_messages enable row level security; alter table public.tool_execution_logs enable row level security; alter table public.audit_logs enable row level security;
create policy "profiles read own" on public.profiles for select using (id=auth.uid()); create policy "profiles update own" on public.profiles for update using (id=auth.uid()) with check(id=auth.uid());
create policy "members read organizations" on public.organizations for select using(public.is_org_member(id)); create policy "owners manage organizations" on public.organizations for all using(public.has_org_role(id,array['owner','admin']::public.organization_role[])) with check(public.has_org_role(id,array['owner','admin']::public.organization_role[]));
create policy "members read memberships" on public.organization_members for select using(public.is_org_member(organization_id)); create policy "admins manage memberships" on public.organization_members for all using(public.has_org_role(organization_id,array['owner','admin']::public.organization_role[])) with check(public.has_org_role(organization_id,array['owner','admin']::public.organization_role[]));
create policy "organization isolation projects" on public.projects for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id) and public.has_org_role(organization_id,array['owner','admin','manager']::public.organization_role[]));
create policy "organization isolation tasks" on public.tasks for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id) and public.has_org_role(organization_id,array['owner','admin','manager','member','support_agent','sales_representative']::public.organization_role[]));
create policy "organization isolation customers" on public.customers for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id) and public.has_org_role(organization_id,array['owner','admin','manager','member','support_agent','sales_representative']::public.organization_role[]));
create policy "organization isolation leads" on public.leads for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id) and public.has_org_role(organization_id,array['owner','admin','manager','member','sales_representative']::public.organization_role[]));
create policy "organization isolation meetings" on public.meetings for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id) and public.has_org_role(organization_id,array['owner','admin','manager','member']::public.organization_role[]));
create policy "organization isolation documents" on public.documents for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id) and public.has_org_role(organization_id,array['owner','admin','manager','member','support_agent','sales_representative']::public.organization_role[]));
create policy "organization isolation support" on public.support_requests for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id) and public.has_org_role(organization_id,array['owner','admin','manager','member','support_agent']::public.organization_role[]));
create policy "organization isolation conversations" on public.conversations for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id)); create policy "organization isolation ai messages" on public.ai_messages for all using(public.is_org_member(organization_id)) with check(public.is_org_member(organization_id)); create policy "organization isolation tool logs" on public.tool_execution_logs for select using(public.is_org_member(organization_id)); create policy "organization isolation audits" on public.audit_logs for select using(public.is_org_member(organization_id));
